// GoogleLoginButton.tsx
import { GoogleLogin, GoogleOAuthProvider } from '@react-oauth/google';
import { useNavigate } from 'react-router-dom';
import { useState } from 'react';
import api from '../services/api';
import { useAuthStore } from '../stores/authStore';

const GoogleLoginButtonContent = () => {
  const navigate = useNavigate();
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const { setAuth } = useAuthStore();

  const handleSuccess = async (credentialResponse: any) => {
    setIsLoading(true);
    setError('');
    try {
      const { data } = await api.post('/auth/google', {
        credential: credentialResponse.credential
      });

      // Stockage des tokens
      localStorage.setItem('access_token', data.access_token);
      localStorage.setItem('refresh_token', data.refresh_token);

      // Mise à jour du store Zustand
      setAuth(data.user, data.access_token);

      // Configuration de l'intercepteur Axios
      api.defaults.headers.common['Authorization'] = `Bearer ${data.access_token}`;

      // Redirection vers la page d'accueil
      navigate('/');
    } catch (err: any) {
      setError(err.response?.data?.message || 'Erreur lors de l\'authentification Google');
    } finally {
      setIsLoading(false);
    }
  };

  const handleError = () => {
    setError('La connexion Google a échoué. Veuillez réessayer.');
  };

  return (
    <div className="flex flex-col items-center gap-3">
      <GoogleLogin
        onSuccess={handleSuccess}
        onError={handleError}
        useOneTap
        theme="filled_blue"
        size="large"
        text="continue_with"
        shape="rectangular"
      />
      {isLoading && <p className="text-gray-500">Connexion en cours...</p>}
      {error && <p className="text-red-500 text-sm">{error}</p>}
    </div>
  );
};

// Composant wrapper avec le provider
export const GoogleLoginButton = () => {
  const clientId = import.meta.env.VITE_GOOGLE_CLIENT_ID;

  if (!clientId) {
    console.error('Google Client ID manquant');
    return null;
  }

  return (
    <GoogleOAuthProvider clientId={clientId}>
      <GoogleLoginButtonContent />
    </GoogleOAuthProvider>
  );
};
