// hooks/useSocialLinking.ts
import { useState } from 'react';
import api from '../services/api';
import { useAuthStore } from '../stores/authStore';

interface LinkResult {
  success: boolean;
  requiresLinking: boolean;
  message: string;
}

export const useSocialLinking = () => {
  const [isLinking, setIsLinking] = useState(false);
  const { user, accessToken } = useAuthStore();

  const handleGoogleSuccess = async (credential: string, existingEmail?: string) => {
    setIsLinking(true);
    try {
      // Étape 1: Tenter la connexion/liaison
      const { data } = await api.post('/auth/google/callback', {
        credential,
        existingEmail,
        linkWithCurrentUser: !!user
      });

      if (data.requiresLinking) {
        // L'email existe déjà mais n'est pas lié à ce compte Google
        return { success: false, requiresLinking: true, message: 'Un compte existe déjà avec cet email. Souhaitez-vous le lier ?' };
      }

      if (data.linked) {
        // Liaison réussie
        localStorage.setItem('access_token', data.access_token);
        useAuthStore.getState().setAuth(data.user, data.access_token);
        return { success: true, requiresLinking: false, message: 'Compte lié avec succès' };
      }

      if (data.newAccount) {
        // Nouveau compte créé
        localStorage.setItem('access_token', data.access_token);
        useAuthStore.getState().setAuth(data.user, data.access_token);
        return { success: true, requiresLinking: false, message: 'Compte créé avec Google' };
      }

      return { success: true, requiresLinking: false, message: 'Connexion réussie' };
    } catch (error) {
      return { success: false, requiresLinking: false, message: 'Erreur lors de l\'authentification' };
    } finally {
      setIsLinking(false);
    }
  };

  const linkAccount = async (credential: string) => {
    if (!user) throw new Error('Utilisateur non connecté');

    setIsLinking(true);
    try {
      await api.post('/auth/google/link', {
        credential,
        userId: user.id
      }, {
        headers: { Authorization: `Bearer ${accessToken}` }
      });
      return { success: true, message: 'Compte Google lié avec succès' };
    } catch (error: any) {
      return { success: false, message: error.response?.data?.message || 'Erreur de liaison' };
    } finally {
      setIsLinking(false);
    }
  };

  return { handleGoogleSuccess, linkAccount, isLinking };
};

