// hooks/useSocialAccounts.ts
import { useState, useEffect } from 'react';
import api from '../services/api';
import { useAuthStore } from '../stores/authStore';

interface SocialAccount {
  id: string;
  provider: 'google' | 'facebook' | 'apple';
  email: string;
  linkedAt: string;
}

export const useSocialAccounts = () => {
  const [accounts, setAccounts] = useState<SocialAccount[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [isLinking, setIsLinking] = useState(false);
  const { user, accessToken } = useAuthStore();

  const fetchAccounts = async () => {
    setIsLoading(true);
    try {
      const { data } = await api.get('/user/social-accounts');
      setAccounts(data);
    } catch (error) {
      console.error('Erreur chargement comptes sociaux', error);
    } finally {
      setIsLoading(false);
    }
  };

  const linkGoogleAccount = async (credential: string) => {
    setIsLinking(true);
    try {
      await api.post('/user/social-accounts/link', { credential, provider: 'google' });
      await fetchAccounts();
      return { success: true, message: 'Compte Google lié avec succès' };
    } catch (error: any) {
      return { success: false, message: error.response?.data?.message || 'Erreur de liaison' };
    } finally {
      setIsLinking(false);
    }
  };

  const unlinkAccount = async (accountId: string) => {
    const account = accounts.find(a => a.id === accountId);
    if (accounts.length === 1 && !user?.passwordHash) {
      throw new Error('Impossible de dissocier le seul moyen de connexion. Veuillez d\'abord définir un mot de passe.');
    }

    try {
      await api.delete(`/user/social-accounts/${accountId}`);
      await fetchAccounts();
      return { success: true, message: `Compte ${account?.provider} dissocié` };
    } catch (error: any) {
      return { success: false, message: error.response?.data?.message || 'Erreur de dissociation' };
    }
  };

  useEffect(() => {
    if (accessToken) fetchAccounts();
  }, [accessToken]);

  return { accounts, isLoading, isLinking, linkGoogleAccount, unlinkAccount, refetch: fetchAccounts };
};

// Composant SocialAccountsManager.tsx
import { GoogleLogin, GoogleOAuthProvider } from '@react-oauth/google';
import { useSocialAccounts } from '../hooks/useSocialAccounts';
import { TrashIcon, LinkIcon } from '@heroicons/react/24/outline';

const SocialAccountsManagerContent = () => {
  const { accounts, isLoading, isLinking, linkGoogleAccount, unlinkAccount } = useSocialAccounts();
  const [message, setMessage] = useState<{ type: 'success' | 'error', text: string } | null>(null);

  const handleGoogleSuccess = async (response: any) => {
    const result = await linkGoogleAccount(response.credential);
    setMessage({ type: result.success ? 'success' : 'error', text: result.message });
    setTimeout(() => setMessage(null), 3000);
  };

  const handleUnlink = async (accountId: string, provider: string) => {
    if (confirm(`Voulez-vous vraiment dissocier votre compte ${provider} ?`)) {
      const result = await unlinkAccount(accountId);
      setMessage({ type: result.success ? 'success' : 'error', text: result.message });
    }
  };

  if (isLoading) return <div className="animate-pulse">Chargement...</div>;

  return (
    <div className="p-4 border rounded-lg">
      <h3 className="text-lg font-semibold mb-4">Comptes sociaux liés</h3>

      {message && (
        <div className={`p-3 mb-4 rounded ${message.type === 'success' ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'}`}>
          {message.text}
        </div>
      )}

      <ul className="space-y-3 mb-6">
        {accounts.map(account => (
          <li key={account.id} className="flex justify-between items-center p-3 bg-gray-50 rounded">
            <div>
              <span className="font-medium capitalize">{account.provider}</span>
              <span className="text-sm text-gray-500 ml-2">{account.email}</span>
              <span className="text-xs text-gray-400 ml-2">Lié le {new Date(account.linkedAt).toLocaleDateString()}</span>
            </div>
            <button
              onClick={() => handleUnlink(account.id, account.provider)}
              className="text-red-600 hover:text-red-800"
              title="Dissocier"
            >
              <TrashIcon className="w-5 h-5" />
            </button>
          </li>
        ))}
      </ul>

      {!accounts.some(a => a.provider === 'google') && (
        <div className="mt-4">
          <p className="text-sm text-gray-600 mb-2">Lier un compte Google :</p>
          <GoogleLogin
            onSuccess={handleGoogleSuccess}
            onError={() => setMessage({ type: 'error', text: 'Échec de la liaison Google' })}
            text="signin_with"
            size="medium"
          />
          {isLinking && <p className="text-sm mt-2">Liaison en cours...</p>}
        </div>
      )}
    </div>
  );
};

export const SocialAccountsManager = () => {
  const clientId = import.meta.env.VITE_GOOGLE_CLIENT_ID;
  if (!clientId) return <p>Configuration OAuth non disponible</p>;
  return (
    <GoogleOAuthProvider clientId={clientId}>
      <SocialAccountsManagerContent />
    </GoogleOAuthProvider>
  );
};
